={
  "query": "Resources | project name, type, location, resourceGroup, tags, sku, properties, id",
  "subscriptions": ["{{ $json.subscriptionId }}"]
}

parameters.jsCode:
const resourcesData = $input.first().json.data;
const resources = resourcesData.rows.map(row => {
  const columns = resourcesData.columns.map(col => col.name);
  let resource = {};
  columns.forEach((col, idx) => {
    resource[col] = row[idx];
  });
  return resource;
});

const costData = $input.last().json.properties;
const costs = costData.rows.map(row => {
  const columns = costData.columns.map(col => col.name);
  let cost = {};
  columns.forEach((col, idx) => {
    cost[col] = row[idx];
  });
  return cost;
});

const merged = resources.map(resource => {
  const resourceCosts = costs.filter(cost => 
    cost.ResourceId && cost.ResourceId.toLowerCase().includes(resource.name.toLowerCase())
  );

  const totalCost = resourceCosts.reduce((sum, cost) => sum + (cost.Cost || 0), 0);

  return {
    resourceName: resource.name,
    resourceType: resource.type,
    resourceGroup: resource.resourceGroup,
    location: resource.location,
    sku: resource.sku,
    tags: resource.tags,
    cost: totalCost.toFixed(2),
    costDetails: resourceCosts
  };
});

merged.sort((a, b) => parseFloat(b.cost) - parseFloat(a.cost));

const totalCost = merged.reduce((sum, r) => sum + parseFloat(r.cost), 0);
const resourceCount = merged.length;
const topCostResources = merged.slice(0, 10);

const costByType = {};
merged.forEach(r => {
  const type = r.resourceType;
  if (!costByType[type]) {
    costByType[type] = { count: 0, cost: 0 };
  }
  costByType[type].count++;
  costByType[type].cost += parseFloat(r.cost);
});

const summary = {
  totalCost: totalCost.toFixed(2),
  resourceCount: resourceCount,
  period: `${$('Set Configuration').item.json.startDate} to ${$('Set Configuration').item.json.endDate}`,
  topCostResources: topCostResources.map(r => ({
    name: r.resourceName,
    type: r.resourceType,
    cost: r.cost
  })),
  costByType: Object.entries(costByType)
    .map(([type, data]) => ({
      type,
      count: data.count,
      cost: data.cost.toFixed(2)
    }))
    .sort((a, b) => parseFloat(b.cost) - parseFloat(a.cost))
};

return [{
  json: {
    summary,
    allResources: merged
  }
}];

const data = $input.first().json;
const summary = data.summary;

let report = `# Azure Resource & Cost Report\n\n`;
report += `**Period:** ${summary.period}\n`;
report += `**Total Cost:** $${summary.totalCost}\n`;
report += `**Total Resources:** ${summary.resourceCount}\n\n`;
report += `## Top 10 Most Expensive Resources\n\n`;
summary.topCostResources.forEach((r, idx) => {
  report += `${idx + 1}. **${r.name}** (${r.type}) - $${r.cost}\n`;
});
report += `\n## Cost by Resource Type\n\n`;
summary.costByType.slice(0, 10).forEach((t, idx) => {
  report += `${idx + 1}. **${t.type}** - ${t.count} resources - $${t.cost}\n`;
});
report += `\n---\n_Generated by n8n on ${new Date().toLocaleString()}_`;

let htmlReport = `
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; margin: 20px; }
    h1 { color: #0078D4; }
    h2 { color: #333; margin-top: 30px; }
    table { border-collapse: collapse; width: 100%; margin-top: 10px; }
    th, td { border: 1px solid #ddd; padding: 8px; text-align: left; }
    th { background-color: #0078D4; color: white; }
    tr:nth-child(even) { background-color: #f2f2f2; }
    .summary { background-color: #e7f3ff; padding: 15px; border-radius: 5px; margin: 20px 0; }
  </style>
</head>
<body>
  <h1>Azure Resource & Cost Report</h1>
  <div class="summary">
    <p><strong>Period:</strong> ${summary.period}</p>
    <p><strong>Total Cost:</strong> $${summary.totalCost}</p>
    <p><strong>Total Resources:</strong> ${summary.resourceCount}</p>
  </div>
  <h2>Top 10 Most Expensive Resources</h2>
  <table>
    <tr><th>#</th><th>Resource Name</th><th>Type</th><th>Cost</th></tr>
`;
summary.topCostResources.forEach((r, idx) => {
  htmlReport += `    <tr><td>${idx + 1}</td><td>${r.name}</td><td>${r.type}</td><td>$${r.cost}</td></tr>\n`;
});
htmlReport += `
  </table>
  <h2>Cost by Resource Type</h2>
  <table>
    <tr><th>#</th><th>Resource Type</th><th>Count</th><th>Total Cost</th></tr>
`;
summary.costByType.slice(0, 10).forEach((t, idx) => {
  htmlReport += `    <tr><td>${idx + 1}</td><td>${t.type}</td><td>${t.count}</td><td>$${t.cost}</td></tr>\n`;
});
htmlReport += `
  </table>
  <p style="margin-top: 30px; color: #666; font-size: 12px;">Generated by n8n on ${new Date().toLocaleString()}</p>
</body>
</html>
`;

return [{
  json: {
    textReport: report,
    htmlReport: htmlReport,
    summary: summary,
    allData: data
  }
}];
